    <line x1="50" y1="200" x2="650" y2="200" stroke="#3f3f46" stroke-dasharray="4,4"/>
    <line x1="230" y1="60" x2="230" y2="340" stroke="#3f3f46" stroke-dasharray="4,4"/>
    <line x1="430" y1="60" x2="430" y2="340" stroke="#3f3f46" stroke-dasharray="4,4"/>
